mapper.select:
SELECT tc.*, c.course_name, c.course_code, ay.year, ay.semester, (CASE WHEN ay.semester = 1 THEN CONCAT(ay.year, ' 第一学期') ELSE CONCAT(ay.year, ' 第二学期') END) as academic_year_name, ct.teacher_name, ct.teacher_id FROM teaching_class tc LEFT JOIN course c ON tc.course_id = c.id LEFT JOIN academic_year ay ON tc.academic_year_id = ay.id LEFT JOIN course_teacher ct ON tc.id = ct.teaching_class_id AND ct.is_main_teacher = 1
AND tc.course_id = #{course_id}
AND tc.academic_year_id = #{academic_year_id}
AND tc.status = #{status}
AND tc.class_code LIKE CONCAT('%', #{class_code}, '%')
ORDER BY ay.year DESC, ay.semester, tc.class_code
